        FlushParallel();
        _stages.Add(new SequentialStageWithResult<TResult>(
            command, _mediator, resultKey));
        return this;
    }

    // 結束 Parallel group，開始下一段 Sequential
    private void FlushParallel()
    {
        if (_pendingParallel.Count == 0) return;
