        return ctx;
    }
}

using MediatR;

namespace CommandPipeline;

// 無順序：與其他 Parallel Stage 一起跑
public class ParallelStage(IEnumerable<IRequest> commands, IMediator mediator) : IChainStage
{
    public async Task ExecuteAsync(ChainContext ctx)
    {
        var tasks = commands.Select(async cmd =>
        {
            try
            {
                await mediator.Send(cmd, ctx.CancellationToken);
            }
            catch (Exception ex)
            {
                ctx.Fail(ex);
            }
        });
        await Task.WhenAll(tasks);
    }
}

using MediatR;
using CommandPipeline.Abstractions;
using CommandPipeline.Core;

namespace CommandPipeline.Stages;

// 無順序：與其他 Parallel Stage 一起跑
public class ParallelStage(IEnumerable<IRequest> commands, IMediator mediator) : IChainStage
{
    public async Task ExecuteAsync(ChainContext ctx)
    {
        var tasks = commands.Select(async cmd =>
        {
            try
            {
                await mediator.Send(cmd, ctx.CancellationToken);
            }
            catch (Exception ex)
            {
                ctx.Fail(ex);
            }
        });
        await Task.WhenAll(tasks);
    }
}

using MediatR;

namespace CommandPipeline;

// 有順序：等前一個完成才執行
public class SequentialStage(IRequest command, IMediator mediator) : IChainStage
{
    public async Task ExecuteAsync(ChainContext ctx)
    {
        if (ctx.IsFailed) return;
        try
        {
            await mediator.Send(command, ctx.CancellationToken);
        }
        catch (Exception ex)
        {
            ctx.Fail(ex);
        }
    }
}

using MediatR;
using CommandPipeline.Abstractions;
using CommandPipeline.Core;

namespace CommandPipeline.Stages;

// 有順序：等前一個完成才執行
public class SequentialStage(IRequest command, IMediator mediator) : IChainStage
{
    public async Task ExecuteAsync(ChainContext ctx)
    {
        if (ctx.IsFailed) return;
        try
        {
            await mediator.Send(command, ctx.CancellationToken);
        }
        catch (Exception ex)
        {
            ctx.Fail(ex);
        }
    }
}

using MediatR;

namespace CommandPipeline;

public class SequentialStageWithResult<TResult>(
    IRequest<TResult> command,
    IMediator mediator,
    string? resultKey) : IChainStage
{
    public async Task ExecuteAsync(ChainContext ctx)
    {
        if (ctx.IsFailed) return;
        try
        {
            var result = await mediator.Send(command, ctx.CancellationToken);
            if (resultKey is not null)
            {
                ctx.Set(resultKey, result);
            }
        }
        catch (Exception ex)
        {
            ctx.Fail(ex);
        }
    }
}

